import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const UserDashboard = () => {
  const [user, setUser] = useState(null);
  const [bookings, setBookings] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const userData = localStorage.getItem('user');
    if (userData) {
      setUser(JSON.parse(userData));
      loadUserBookings();
    } else {
      navigate('/login');
    }
  }, [navigate]);

  const loadUserBookings = () => {
    // Mock booking history
    const mockBookings = [
      {
        id: 'BK123456',
        busName: 'Express Travels',
        route: 'New York → Los Angeles',
        date: '2024-04-15',
        departure: '08:00 AM',
        arrival: '02:00 PM',
        seats: ['12', '13'],
        totalAmount: 900,
        status: 'Confirmed',
        bookingDate: '2024-04-01'
      },
      {
        id: 'BK789012',
        busName: 'Royal Bus Service',
        route: 'Chicago → Houston',
        date: '2024-03-20',
        departure: '10:30 AM',
        arrival: '05:30 PM',
        seats: ['5'],
        totalAmount: 280,
        status: 'Completed',
        bookingDate: '2024-03-15'
      }
    ];
    setBookings(mockBookings);
  };

  const handleTrackBus = (booking) => {
    navigate('/track-bus', { state: { booking } });
  };

  const handleCancelBooking = (bookingId) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      setBookings(bookings.filter(b => b.id !== bookingId));
      alert('Booking cancelled successfully');
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'Confirmed': return '#28a745';
      case 'Completed': return '#6c757d';
      case 'Cancelled': return '#dc3545';
      default: return '#ffc107';
    }
  };

  if (!user) {
    return <div>Loading...</div>;
  }

  return (
    <div className="container">
      <div className="card">
        <h2>Welcome, {user.name}!</h2>
        <p style={{ color: '#666' }}>Manage your bus bookings and travel plans</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px', marginBottom: '30px' }}>
        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#007bff', marginBottom: '10px' }}>🚌 Book a Bus</h3>
          <p>Search and book buses for your journey</p>
          <button className="btn" onClick={() => navigate('/search')} style={{ marginTop: '10px' }}>
            Search Buses
          </button>
        </div>

        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#007bff', marginBottom: '10px' }}>📋 My Bookings</h3>
          <p>View and manage your bookings</p>
          <div style={{ marginTop: '10px', fontSize: '24px', fontWeight: 'bold', color: '#007bff' }}>
            {bookings.length}
          </div>
        </div>

        <div className="card" style={{ textAlign: 'center' }}>
          <h3 style={{ color: '#007bff', marginBottom: '10px' }}>📍 Track Bus</h3>
          <p>Track your bus in real-time</p>
          <button className="btn btn-secondary" onClick={() => navigate('/track-bus')} style={{ marginTop: '10px' }}>
            Track Now
          </button>
        </div>
      </div>

      <div className="card">
        <h3>Recent Bookings</h3>
        {bookings.length === 0 ? (
          <p>No bookings found. Book your first bus now!</p>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {bookings.map(booking => (
              <div key={booking.id} className="card" style={{ border: '1px solid #ddd' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr auto', gap: '20px', alignItems: 'center' }}>
                  <div>
                    <h4 style={{ margin: '0 0 5px 0' }}>{booking.busName}</h4>
                    <p style={{ margin: '0', color: '#666', fontSize: '14px' }}>{booking.route}</p>
                    <p style={{ margin: '5px 0 0 0', fontSize: '12px', color: '#666' }}>
                      Seats: {booking.seats.join(', ')} | Amount: ₹{booking.totalAmount}
                    </p>
                  </div>

                  <div>
                    <div style={{ fontWeight: 'bold' }}>{booking.date}</div>
                    <div style={{ fontSize: '12px', color: '#666' }}>{booking.departure} - {booking.arrival}</div>
                  </div>

                  <div>
                    <div style={{ 
                      padding: '4px 8px', 
                      borderRadius: '4px', 
                      backgroundColor: getStatusColor(booking.status),
                      color: 'white',
                      fontSize: '12px',
                      fontWeight: 'bold',
                      textAlign: 'center'
                    }}>
                      {booking.status}
                    </div>
                  </div>

                  <div>
                    <div style={{ display: 'flex', gap: '5px' }}>
                      {booking.status === 'Confirmed' && (
                        <>
                          <button
                            className="btn btn-secondary"
                            onClick={() => handleTrackBus(booking)}
                            style={{ padding: '5px 10px', fontSize: '12px' }}
                          >
                            Track
                          </button>
                          <button
                            className="btn"
                            onClick={() => handleCancelBooking(booking.id)}
                            style={{ 
                              padding: '5px 10px', 
                              fontSize: '12px',
                              backgroundColor: '#dc3545'
                            }}
                          >
                            Cancel
                          </button>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default UserDashboard;
